* {
  box-sizing: border-box;
}

html,
body,
#root {
  width: 100%;
  height: 100%;
}

body {
  margin: 0;
  min-width: 0;
  min-height: 0;
  overflow: hidden;
  background:
    linear-gradient(145deg, rgb(255 255 255 / 3%) 0%, transparent 34%),
    linear-gradient(180deg, var(--relay-chrome) 0%, var(--relay-bg) 54%);
  color: var(--relay-text);
  font-size: var(--relay-text-base);
  line-height: 1.5;
}

button,
input,
textarea,
select {
  font: inherit;
}

button {
  min-height: 32px;
  border: 1px solid transparent;
  border-radius: var(--relay-radius-md);
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text);
  padding: 0 11px;
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: var(--relay-space-2);
  cursor: pointer;
  box-shadow:
    var(--relay-inset-highlight),
    0 8px 18px rgb(0 0 0 / 8%);
  transition:
    background-color 160ms var(--relay-ease),
    border-color 160ms var(--relay-ease),
    color 160ms var(--relay-ease),
    opacity 160ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease),
    transform 180ms var(--relay-spring);
}

button:hover {
  background: rgb(255 255 255 / 8%);
  box-shadow:
    var(--relay-inset-highlight),
    0 10px 26px rgb(0 0 0 / 16%);
  transform: translateY(-1px);
}

button:active {
  transform: translateY(0);
  background: var(--relay-surface-active);
  box-shadow: var(--relay-inset-highlight);
}

button:focus-visible,
input:focus-visible,
textarea:focus-visible,
select:focus-visible {
  outline: none;
  box-shadow: var(--relay-focus-ring);
}

button:disabled {
  cursor: not-allowed;
  opacity: 0.52;
  transform: none;
}

button svg {
  flex: 0 0 auto;
  opacity: 0.86;
}

input,
textarea,
select {
  width: 100%;
  border: 1px solid transparent;
  border-radius: var(--relay-radius-md);
  background: var(--relay-input);
  color: var(--relay-text);
  padding: 8px 10px;
  outline: none;
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 4%);
  transition:
    background-color 160ms var(--relay-ease),
    border-color 160ms var(--relay-ease),
    box-shadow 180ms var(--relay-ease);
}

input::placeholder,
textarea::placeholder {
  color: var(--relay-text-subtle);
}

input:hover,
textarea:hover,
select:hover {
  box-shadow:
    var(--relay-inset-highlight),
    inset 0 0 0 1px rgb(255 255 255 / 8%);
}

textarea {
  min-height: 132px;
  resize: vertical;
  line-height: 1.45;
}

select {
  color: var(--relay-text);
}

option {
  background: var(--relay-popover);
  color: var(--relay-text);
}

pre,
code {
  font-family: var(--relay-font-mono);
}

kbd {
  min-height: 18px;
  border: 0;
  border-radius: var(--relay-radius-xs);
  background: rgb(255 255 255 / 13%);
  color: currentColor;
  padding: 1px 5px;
  font-family: var(--relay-font-mono);
  font-size: var(--relay-text-xs);
  font-weight: 650;
  line-height: 1.25;
  white-space: nowrap;
}

.sr-only {
  position: absolute;
  width: 1px;
  height: 1px;
  overflow: hidden;
  clip: rect(0, 0, 0, 0);
  clip-path: inset(50%);
  white-space: nowrap;
}

::-webkit-scrollbar {
  width: 8px;
  height: 8px;
}

::-webkit-scrollbar-track {
  background: transparent;
}

::-webkit-scrollbar-thumb {
  border: 2px solid transparent;
  border-radius: 999px;
  background: rgb(255 255 255 / 18%);
  background-clip: padding-box;
}

::-webkit-scrollbar-thumb:hover {
  background: rgb(255 255 255 / 28%);
  background-clip: padding-box;
}

