.ticket-card {
  position: relative;
  border: 1px solid var(--relay-border-strong);
  border-radius: var(--relay-radius-md);
  background: var(--relay-surface-2);
  box-shadow: none;
  transition:
    opacity 180ms var(--relay-ease),
    filter 180ms var(--relay-ease),
    border-color 180ms var(--relay-ease);
}

.ticket-card:hover {
  background: var(--relay-surface-2);
  border-color: var(--relay-border-strong);
  box-shadow: none;
}

.ticket-card.keyboard-selected {
  background: var(--relay-surface-2);
  border-color: color-mix(in srgb, var(--relay-primary) 58%, var(--relay-border-strong));
  box-shadow: none;
}

.ticket-card:focus-within {
  border-color: color-mix(in srgb, var(--relay-ring) 64%, var(--relay-border-strong));
  box-shadow: none;
}

.board.board-has-focus .ticket-card:not(.keyboard-selected) {
  filter: saturate(0.72);
  opacity: 0.56;
}

.ticket-card.dragging {
  z-index: 10;
  opacity: 0.92;
  border-color: color-mix(in srgb, var(--relay-primary) 64%, var(--relay-border-strong));
  box-shadow: none;
}

.card-open {
  width: 100%;
  min-height: 0;
  display: block;
  text-align: left;
  border: 0;
  background: transparent;
  padding: 14px 42px 14px 14px;
  box-shadow: none;
  transition: none;
}

.card-open:hover {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:active {
  background: transparent;
  box-shadow: none;
  transform: none;
}

.card-open:focus-visible {
  background: transparent;
  box-shadow: none;
}

.card-title {
  margin-bottom: 8px;
  color: var(--relay-text);
  font-weight: 560;
  line-height: 1.32;
}

.card-excerpt {
  display: -webkit-box;
  overflow: hidden;
  -webkit-box-orient: vertical;
  -webkit-line-clamp: 4;
  margin: 0;
  color: rgb(255 255 255 / 66%);
  font-size: var(--relay-text-md);
  line-height: 1.5;
}

.card-meta,
.labels,
.danger-row,
.detail-actions {
  display: flex;
  align-items: center;
  gap: var(--relay-space-2);
  flex-wrap: wrap;
}

.card-meta {
  margin-top: 12px;
  opacity: 0.82;
}

.priority,
.run-pill,
.labels span {
  min-height: 21px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5.5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
}

.git-metadata {
  min-width: 0;
  max-width: min(100%, 360px);
  min-height: 22px;
  border: 0;
  border-radius: 999px;
  background: rgb(255 255 255 / 5%);
  color: var(--relay-text-muted);
  padding: 3px 8px;
  display: inline-flex;
  align-items: center;
  gap: 6px;
  font-size: var(--relay-text-sm);
  line-height: 1.2;
  white-space: nowrap;
}

.git-metadata svg {
  flex: 0 0 auto;
}

.git-metadata > span {
  min-width: 0;
  overflow: hidden;
  text-overflow: ellipsis;
}

.git-metadata.compact {
  max-width: 170px;
  padding-inline: 6px;
}

.git-metadata.git-loading {
  color: var(--relay-text-subtle);
}

.git-metadata.git-ready {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.git-metadata.git-ready.dirty {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
}

.git-metadata.git-not_git,
.git-metadata.git-missing {
  background: color-mix(in srgb, var(--relay-surface-2) 70%, transparent);
  color: var(--relay-text-subtle);
}

.git-metadata.git-unavailable,
.git-metadata.git-error {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.high,
.priority.urgent {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.priority.low {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.running,
.run-pill.blocked,
.run-pill.drafting {
  background: var(--relay-warning-muted);
  color: var(--relay-warning-text);
  box-shadow: inset 0 0 0 1px color-mix(in srgb, var(--relay-warning) 18%, transparent);
}

.run-pill.completed {
  background: var(--relay-success-muted);
  color: var(--relay-success-text);
}

.run-pill.failed,
.run-pill.cancelled {
  background: var(--relay-danger-muted);
  color: var(--relay-danger-text);
}

.labels {
  margin-top: 10px;
  max-height: none;
  overflow: visible;
  opacity: 1;
  transform: none;
}

.labels .label-overflow {
  color: var(--relay-text-subtle);
}

.drag-handle {
  position: absolute;
  top: var(--relay-space-2);
  right: var(--relay-space-2);
  width: 28px;
  min-height: 28px;
  padding: 0;
  border-color: transparent;
  background: transparent;
  color: var(--relay-text-subtle);
  box-shadow: none;
  opacity: 1;
  transition:
    color 160ms var(--relay-ease),
    background-color 160ms var(--relay-ease);
}

.drag-handle:hover {
  color: var(--relay-text);
  background: rgb(255 255 255 / 7%);
  box-shadow: none;
  transform: none;
}

.status-rail {
  position: fixed;
  right: 14px;
  bottom: 14px;
  pointer-events: none;
}
